var e=JSON.parse(`[{"id":"L12_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"……이상. 클리포트 게임에 대한 보고를 마치겠습니다, 메데이아 경.","JPN":"……以上、クリフォトゲームの報告を終わります。メデイア卿。","ENG":"...That concludes the report on the Qliphoth Game, Dame Medea.","TWN":"……以上。關於逆卡巴拉遊戲的報告結束，美狄亞。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"고생하셨어요. 일의 전말을 듣고 나니 갑작스러운 긴급 소집도 납득이 가네요.","JPN":"お疲れさまでした。事情をうかがってようやく、あの突然の緊急招集にも合点がいきましたわ。","ENG":"Good work. Now that I've heard the full story, I can see why we were urgently called in.","TWN":"辛苦了。聽完事情的經過後，可以理解為什麼需要緊急召集了。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"현재 에스테로사 경의 상태는 어떤가요?","JPN":"現在、エステロサ卿のご様子は？","ENG":"What's Dame Esterosa's condition?","TWN":"目前艾斯特洛索的狀態如何？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"같은 자리에 고개를 숙이신 채 움직이지 않고 계십니다.","JPN":"じっとうつむいた姿勢のまま、動かれません。","ENG":"She remains in the same spot, head bowed, completely still.","TWN":"在同一個位子低著頭，一動不動。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"아무래도 버밍엄 교수의 죽음이 여간 충격이셨던 것 같습니다.","JPN":"バーミンガム教授の死がかなりショックだったのだと思います。","ENG":"It seems Professor Birmingham's death was a severe shock to her.","TWN":"看來伯明罕教授的去世是個不小的打擊。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"그야 그렇겠죠. 그녀를 기사단에 들인 후견인은 다름아닌 버밍엄 교수였으니까요.","JPN":"それはそうでしょうね。彼女を騎士団に迎え入れる際に後押ししたのが、他ならぬバーミンガム教授でしたもの。","ENG":"Of course it was. After all, he was the one who sponsored her entry into the Order.","TWN":"那當然了。畢竟推薦她加入騎士團的導師正是伯明罕教授。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"심정을 이해못할 것은 아니나… 하필이면 원로원의 판단을 거스르다니.","JPN":"気持ちはわからなくもありませんが……よりによって元老院の判断に背くなんて。","ENG":"I don't blame her for how she feels... but defying the Elder Council's decision?","TWN":"我並不是不能理解你的心情……但為何偏偏要違背元老院的判斷呢。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"명분이 있었다 한들, 이번만큼은 치기어린 판단이었네요.","JPN":"いくら大義名分があったとはいえ、今回の判断は迂闊でした。","ENG":"Even with some justification, this time, that was a reckless move.","TWN":"即便有理由，這次也只是幼稚的判斷呢。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"어… 그런데 아까부터 엄청 굳어 계시네요.","JPN":"あら……ところで、先程からずいぶんお顔が強張っていますね。","ENG":"Uh... You've been standing there awfully stiff. Did I make you uncomfortable somehow?","TWN":"呃……不過你從剛才開始就一直僵著呢。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"혹시 제가 불편할 짓이라도?","JPN":"もしかして私が何か気に障ることでも？","ENG":"Did I say something wrong?","TWN":"難道我做了讓你不舒服的事嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"아, 아닙니다! 별을 추종하는 기사로서 전 세대 분을 만난 것이 영광스러워서 그만…!","JPN":"い、いいえ！　星の追従者たる騎士として、前の世代の方にお会いできたのが光栄で、つい……！","ENG":"N-no, ma'am! It's just... As a knight who follows the stars, I'm honored to meet someone from the previous generation...!","TWN":"啊，不是的！作為追隨星辰的騎士，能見到前輩你是我的榮幸，所以才……！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"비록 전임 기사단장으로 인해 의미가 퇴색되었지만, 전 세대 분들은 유례없는 황금세대라 불린 분들이 아닙니까?","JPN":"前騎士団長のことでその意味が薄れてしまったとはいえ、先代の方々は、かつて例のない黄金世代と呼ばれた方々ではありませんか。","ENG":"Though its significance may have been tarnished by the former commander, were not the previous generation hailed as an unparalleled golden generation?","TWN":"雖然由於前任騎士團長的原因意義有所減退，但上一代的人們不是被稱為史無前例的黃金一代嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"그 중 백양궁의 기사인 메데이아 경을 만나다니… 이런 상황이지만 영광스러울 따름입니다!","JPN":"その中でも白羊宮の騎士であるメデイア卿に会えるなんて……こんな状況ですが、光栄の至りです！","ENG":"And meeting the Knight of Aries herself... Dame Medea, it's an honor, despite the circumstances!","TWN":"其中竟然遇到了白羊宮的騎士美狄亞……雖然是在這樣的情況下，但仍感到無比榮幸！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"과장된 표현이에요. 아직 견습이지만 지금 양자리의 기사는 제가 아니라 한솔이고요.\xA0\xA0\xA0","JPN":"おおげさですわ。まだ見習いとはいえ、今牡羊座の騎士を勤めているのはイチロウです。\xA0\xA0\xA0","ENG":"You flatter me. I may still hold the Armament due to family ties, but the current Knight of Aries is Hansol, not me.\xA0\xA0\xA0","TWN":"這是誇張的說法。我還是見習生，現在的白羊座騎士不是我，而是楊瀚。\xA0\xA0\xA0"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"가문이 얽힌 문제라 무구는 제 손에 있지만 그 점은 유의해주세요.","JPN":"家門内の事情で武具はまだ私が所持していますが、その点だけはお忘れなきよう。","ENG":"Please keep that in mind.","TWN":"因為涉及家族問題，武器雖然在我手上，但請注意這一點。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"LAUGH2"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"넵. 주의하겠습니다!!","JPN":"はっ、気をつけます！！","ENG":"Understood! I'll be careful!","TWN":"好，我會注意的！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"LAUGH2"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"아하하… 그럼, 현장으로 안내를 부탁드릴게요.","JPN":"あはは……では、現場へ案内をお願いしますわ。","ENG":"Ahaha... Well then, if you don't mind, please lead the way to the site.","TWN":"啊哈哈……那麼，請帶我去現場吧。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"알렌 버밍엄…… 카운터 아카데미 소속의 전술학 교사.","JPN":"アレン・バーミンガム……カウンターアカデミー所属の戦術学教師。","ENG":"Allen Birmingham... the tactics instructor from Counter Academy.","TWN":"艾倫·伯明罕……制裁者學院所屬的戰術學教師。"},"stage":{"bg":"THRONE","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"이전부터 그는 카운터 전술학 이외에 별의 무구의 연구에도 지대한 관심을 보였지.","JPN":"以前から彼は、カウンター戦術学の他に、星の武具の研究にも多大な関心を示していた。","ENG":"Even back then, his interest extended beyond Counter tactics, being deeply invested in researching the Star Armaments.","TWN":"從以前開始，他不僅對制裁者戰紀戰術學感興趣，還對星之武具的研究表現出極大的關注。"},"stage":{"bg":"THRONE","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"만약 기사단에 협력한 게 흑심이었다면, 앞뒤는 맞아. 그들의 기예 역시 기사단과 것과 유사했으니.","JPN":"騎士団に協力したのも何か魂胆があってのこと、と思えば辻褄が合うわ。彼らの技も騎士団のものと似ていたし。","ENG":"If he aided the knights with ill intent, the timeline fits. Their techniques were suspiciously similar to ours.","TWN":"如果與騎士團合作是出於私心，那就說得通了。他們的技藝也與騎士團相似。"},"stage":{"bg":"THRONE","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"문제는…….","JPN":"問題は……","ENG":"The problem is...","TWN":"問題是……"},"stage":{"bg":"THRONE","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_QM_NULL","text":{"KOREA":"겉모습과 달리, 그들의 무구가 관리국의 기술을 뛰어넘는다는 점이겠죠.","JPN":"見た目とは違い、彼らの武具が管理局の技術を遥かに超えているということでしょうね。","ENG":"That their Armaments surpass even the Administration's technology, despite appearances.","TWN":"與外表不同的是，他們的武器裝備超越了管理局的技術水準。"},"stage":{"bg":"THRONE","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_QM_NULL","text":{"KOREA":"그러니 마왕의 사도가 조디악 나이츠와 번거로운 유착 관계를 유지할 필요도 없고요.","JPN":"だから魔王の使徒がわざわざ、ゾディアックナイツと煩わしい癒着関係を保つ必要もない。","ENG":"Which means the Demon Lord's Apostle had no need to keep up a messy alliance with the Zodiac Knights.","TWN":"所以魔王的使徒也不需要與十二宮騎士團維持麻煩的關係。"},"stage":{"bg":"THRONE","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};